// package-lock-manager.js
// A comprehensive script and utility for managing package-lock.json
// in Node.js projects for consistent, reproducible builds.

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

class PackageLockManager {
  constructor(projectRoot = process.cwd()) {
    this.projectRoot = projectRoot;
    this.packageJsonPath = path.join(projectRoot, 'package.json');
    this.packageLockPath = path.join(projectRoot, 'package-lock.json');
    this.lockHashPath = path.join(projectRoot, '.lock-hash');
    this.logEntries = [];
  }

  // ============================================================
  // SECTION 1: Lock File Generation & Validation
  // ============================================================

  /**
   * Generate a fresh package-lock.json from package.json
   * This should be run when:
   * - Starting a new project
   * - The lock file is corrupted or missing
   * - You want to regenerate all dependency resolutions
   */
  generateLockFile() {
    this.log('INFO', 'Generating fresh package-lock.json...');

    if (!fs.existsSync(this.packageJsonPath)) {
      throw new Error('package.json not found. Initialize your project first with: npm init');
    }

    try {
      // Remove existing node_modules and lock file for clean generation
      this.log('INFO', 'Cleaning existing artifacts...');
      this.cleanArtifacts();

      // Generate lock file with npm install
      this.log('INFO', 'Running npm install to generate lock file...');
      execSync('npm install', {
        cwd: this.projectRoot,
        stdio: 'pipe',
        env: { ...process.env, NODE_ENV: 'development' }
      });

      // Validate the generated lock file
      this.validateLockFile();

      // Generate and store hash for integrity checking
      this.storeLockHash();

      this.log('SUCCESS', 'package-lock.json generated successfully');
      return true;
    } catch (error) {
      this.log('ERROR', `Failed to generate lock file: ${error.message}`);
      throw error;
    }
  }

  /**
   * Validate that package-lock.json is in sync with package.json
   * Returns detailed report of any discrepancies
   */
  validateLockFile() {
    this.log('INFO', 'Validating package-lock.json...');

    if (!fs.existsSync(this.packageLockPath)) {
      throw new Error(
        'package-lock.json not found.\n' +
        'Run "npm install" to generate it, or use manager.generateLockFile()'
      );
    }

    const packageJson = JSON.parse(fs.readFileSync(this.packageJsonPath, 'utf8'));
    const packageLock = JSON.parse(fs.readFileSync(this.packageLockPath, 'utf8'));

    const report = {
      valid: true,
      lockfileVersion: packageLock.lockfileVersion,
      issues: [],
      warnings: [],
      stats: {
        totalPackages: 0,
        directDependencies: 0,
        devDependencies: 0,
        missingInLock: [],
        extraInLock: [],
        versionMismatches: []
      }
    };

    // Check lockfile version
    if (packageLock.lockfileVersion < 2) {
      report.warnings.push(
        `Lockfile version ${packageLock.lockfileVersion} detected. ` +
        'Consider upgrading to npm 7+ for lockfile version 2/3 which includes better resolution.'
      );
    }

    // Check name and version consistency
    if (packageJson.name !== packageLock.name) {
      report.issues.push(`Package name mismatch: package.json="${packageJson.name}" vs lock="${packageLock.name}"`);
      report.valid = false;
    }

    if (packageJson.version !== packageLock.version) {
      report.warnings.push(`Version mismatch: package.json="${packageJson.version}" vs lock="${packageLock.version}"`);
    }

    // Validate direct dependencies
    const allDeps = {
      ...(packageJson.dependencies || {}),
      ...(packageJson.devDependencies || {})
    };

    const lockPackages = packageLock.packages || {};
    const lockDependencies = packageLock.dependencies || {};

    // For lockfileVersion 2/3, check the packages field
    if (packageLock.lockfileVersion >= 2) {
      const rootPackage = lockPackages[''] || {};
      const rootDeps = {
        ...(rootPackage.dependencies || {}),
        ...(rootPackage.devDependencies || {})
      };

      for (const [name, versionRange] of Object.entries(allDeps)) {
        report.stats.directDependencies++;
        if (!rootDeps[name]) {
          report.stats.missingInLock.push(name);
          report.issues.push(`Dependency "${name}" is in package.json but missing from lock file`);
          report.valid = false;
        } else if (rootDeps[name] !== versionRange) {
          report.stats.versionMismatches.push({
            name,
            packageJson: versionRange,
            lockFile: rootDeps[name]
          });
          report.issues.push(
            `Version range mismatch for "${name}": package.json="${versionRange}" vs lock="${rootDeps[name]}"`
          );
          report.valid = false;
        }
      }
    }

    // Count total packages
    if (packageLock.lockfileVersion >= 2) {
      report.stats.totalPackages = Object.keys(lockPackages).filter(k => k !== '').length;
    } else {
      report.stats.totalPackages = Object.keys(lockDependencies).length;
    }

    // Run npm's own validation
    try {
      execSync('npm ls --json 2>/dev/null', {
        cwd: this.projectRoot,
        stdio: 'pipe'
      });
    } catch (error) {
      // npm ls returns non-zero exit code if there are issues
      try {
        const lsOutput = JSON.parse(error.stdout.toString());
        if (lsOutput.problems && lsOutput.problems.length > 0) {
          report.warnings.push(...lsOutput.problems.map(p => `npm ls: ${p}`));
        }
      } catch (parseError) {
        report.warnings.push('Could not parse npm ls output for additional validation');
      }
    }

    this.log(
      report.valid ? 'SUCCESS' : 'WARNING',
      `Validation complete: ${report.issues.length} issues, ${report.warnings.length} warnings, ${report.stats.totalPackages} total packages`
    );

    return report;
  }

  /**
   * Check integrity of lock file using stored hash
   */
  checkIntegrity() {
    this.log('INFO', 'Checking lock file integrity...');

    if (!fs.existsSync(this.lockHashPath)) {
      this.log('WARNING', 'No stored hash found. Run storeLockHash() to create baseline.');
      return { intact: false, reason: 'no_baseline' };
    }

    const storedHash = fs.readFileSync(this.lockHashPath, 'utf8').trim();
    const currentHash = this.computeLockHash();

    if (storedHash === currentHash) {
      this.log('SUCCESS', 'Lock file integrity verified - no modifications detected');
      return { intact: true };
    } else {
      this.log('WARNING', 'Lock file has been modified since last hash was stored');
      return {
        intact: false,
        reason: 'hash_mismatch',
        storedHash,
        currentHash
      };
    }
  }

  // ============================================================
  // SECTION 2: Dependency Management Operations
  // ============================================================

  /**
   * Install dependencies using the lock file (CI-safe)
   * Uses `npm ci` which is the recommended approach for CI/CD pipelines
   *
   * npm ci vs npm install:
   * - npm ci: Deletes node_modules, installs EXACTLY what's in lock file
   * - npm install: May update lock file if package.json has changed
   */
  ciInstall(options = {}) {
    const {
      production = false,
      ignoreScripts = false,
      audit = true
    } = options;

    this.log('INFO', 'Running CI-safe install (npm ci)...');

    if (!fs.existsSync(this.packageLockPath)) {
      throw new Error(
        'package-lock.json is required for npm ci.\n' +
        'Generate it first with: npm install'
      );
    }

    let command = 'npm ci';

    if (production) {
      command += ' --omit=dev';
      this.log('INFO', 'Production mode: devDependencies will be excluded');
    }

    if (ignoreScripts) {
      command += ' --ignore-scripts';
      this.log('INFO', 'Lifecycle scripts will be skipped');
    }

    if (!audit) {
      command += ' --no-audit';
    }

    try {
      const startTime = Date.now();
      execSync(command, {
        cwd: this.projectRoot,
        stdio: 'inherit',
        env: { ...process.env }
      });
      const duration = ((Date.now() - startTime) / 1000).toFixed(2);
      this.log('SUCCESS', `CI install completed in ${duration}s`);
      return true;
    } catch (error) {
      this.log('ERROR', `CI install failed: ${error.message}`);
      throw new Error(
        'npm ci failed. Common causes:\n' +
        '1. package-lock.json is out of sync with package.json\n' +
        '2. npm cache is corrupted (try: npm cache clean --force)\n' +
        '3. Registry is unreachable\n' +
        'Fix: Run "npm install" locally and commit the updated lock file.'
      );
    }
  }

  /**
   * Add a new dependency and update lock file properly
   */
  addDependency(packageName, options = {}) {
    const {
      dev = false,
      exact = false,
      peer = false
    } = options;

    this.log('INFO', `Adding dependency: ${packageName}`);

    let command = `npm install ${packageName}`;

    if (dev) command += ' --save-dev';
    if (exact) command += ' --save-exact';
    if (peer) command += ' --save-peer';

    try {
      execSync(command, {
        cwd: this.projectRoot,
        stdio: 'pipe'
      });

      // Update stored hash
      this.storeLockHash();

      this.log('SUCCESS', `Added ${packageName} and updated lock file`);

      // Return info about what was installed
      return this.getPackageInfo(packageName.split('@')[0]);
    } catch (error) {
      this.log('ERROR', `Failed to add ${packageName}: ${error.message}`);
      throw error;
    }
  }

  /**
   * Remove a dependency and update lock file
   */
  removeDependency(packageName) {
    this.log('INFO', `Removing dependency: ${packageName}`);

    try {
      execSync(`npm uninstall ${packageName}`, {
        cwd: this.projectRoot,
        stdio: 'pipe'
      });

      this.storeLockHash();
      this.log('SUCCESS', `Removed ${packageName} and updated lock file`);
      return true;
    } catch (error) {
      this.log('ERROR', `Failed to remove ${packageName}: ${error.message}`);
      throw error;
    }
  }

  /**
   * Update dependencies while respecting semver ranges in package.json
   * This will update the lock file with newer versions within allowed ranges
   */
  updateDependencies(options = {}) {
    const {
      packages = [],      // specific packages to update, empty = all
      dry = false,         // just show what would be updated
      major = false        // allow major version updates (dangerous!)
    } = options;

    this.log('INFO', 'Checking for dependency updates...');

    // First, show what's outdated
    try {
      const outdatedOutput = execSync('npm outdated --json 2>/dev/null || true', {
        cwd: this.projectRoot,
        stdio: 'pipe'
      }).toString();

      let outdated = {};
      try {
        outdated = JSON.parse(outdatedOutput || '{}');
      } catch (e) {
        outdated = {};
      }

      const outdatedList = Object.entries(outdated).map(([name, info]) => ({
        name,
        current: info.current,
        wanted: info.wanted,
        latest: info.latest,
        type: info.type,
        hasMajorUpdate: info.latest !== info.wanted
      }));

      if (outdatedList.length === 0) {
        this.log('SUCCESS', 'All dependencies are up to date');
        return { updated: false, packages: [] };
      }

      this.log('INFO', `Found ${outdatedList.length} outdated packages:`);
      outdatedList.forEach(pkg => {
        this.log('INFO', `  ${pkg.name}: ${pkg.current} → ${pkg.wanted} (latest: ${pkg.latest})`);
      });

      if (dry) {
        return { updated: false, dryRun: true, outdated: outdatedList };
      }

      // Perform the update
      let updateCommand = 'npm update';

      if (packages.length > 0) {
        updateCommand += ' ' + packages.join(' ');
      }

      execSync(updateCommand, {
        cwd: this.projectRoot,
        stdio: 'pipe'
      });

      // If major updates are requested, use npm install with @latest
      if (major && packages.length > 0) {
        const latestCommand = packages.map(p => `${p}@latest`).join(' ');
        execSync(`npm install ${latestCommand}`, {
          cwd: this.projectRoot,
          stdio: 'pipe'
        });
      }

      this.storeLockHash();
      this.log('SUCCESS', 'Dependencies updated and lock file refreshed');

      return { updated: true, packages: outdatedList };
    } catch (error) {
      this.log('ERROR', `Update failed: ${error.message}`);
      throw error;
    }
  }

  // ============================================================
  // SECTION 3: Security & Audit
  // ============================================================

  /**
   * Run security audit on locked dependencies
   */
  auditDependencies(options = {}) {
    const { fix = false, production = false } = options;

    this.log('INFO', 'Running security audit on locked dependencies...');

    try {
      let command = fix ? 'npm audit fix --json' : 'npm audit --json';
      if (production) command += ' --omit=dev';

      const output = execSync(command, {
        cwd: this.projectRoot,
        stdio: 'pipe',
        env: { ...process.env }
      }).toString();

      const auditResult = JSON.parse(output);

      const report = {
        vulnerabilities: auditResult.metadata?.vulnerabilities || {},
        totalVulnerabilities: auditResult.metadata?.vulnerabilities
          ? Object.values(auditResult.metadata.vulnerabilities).reduce((a, b) => a + b, 0)
          : 0,
        advisories: auditResult.advisories || {},
        fixed: fix ? (auditResult.audit?.auditReportVersion || 'check output') : 'N/A'
      };

      if (report.totalVulnerabilities === 0) {
        this.log('SUCCESS', 'No vulnerabilities found');
      } else {
        this.log('WARNING', `Found ${report.totalVulnerabilities} vulnerabilities`);
        const vulns = report.vulnerabilities;
        if (vulns.critical) this.log('ERROR', `  Critical: ${vulns.critical}`);
        if (vulns.high) this.log('ERROR', `  High: ${vulns.high}`);
        if (vulns.moderate) this.log('WARNING', `  Moderate: ${vulns.moderate}`);
        if (vulns.low) this.log('INFO', `  Low: ${vulns.low}`);
      }

      if (fix) {
        this.storeLockHash();
      }

      return report;
    } catch (error) {
      // npm audit exits with non-zero when vulnerabilities exist
      try {
        const auditResult = JSON.parse(error.stdout.toString());
        this.log('WARNING', 'Audit completed with findings');
        return auditResult;
      } catch (parseError) {
        this.log('ERROR', `Audit failed: ${error.message}`);
        throw error;
      }
    }
  }

  // ============================================================
  // SECTION 4: Lock File Analysis & Reporting
  // ============================================================

  /**
   * Analyze the lock file and produce a detailed report
   */
  analyzeLockFile() {
    this.log('INFO', 'Analyzing package-lock.json...');

    if (!fs.existsSync(this.packageLockPath)) {
      throw new Error('package-lock.json not found');
    }

    const lockData = JSON.parse(fs.readFileSync(this.packageLockPath, 'utf8'));
    const packageData = JSON.parse(fs.readFileSync(this.packageJsonPath, 'utf8'));

    const analysis = {
      project: {
        name: lockData.name,
        version: lockData.version,
        lockfileVersion: lockData.lockfileVersion,
        nodeVersion: process.version,
        npmVersion: this.getNpmVersion()
      },
      dependencies: {
        direct: Object.keys(packageData.dependencies || {}).length,
        dev: Object.keys(packageData.devDependencies || {}).length,
        peer: Object.keys(packageData.peerDependencies || {}).length,
        optional: Object.keys(packageData.optionalDependencies || {}).length,
        total: 0,
        tree: {}
      },
      registries: new Set(),
      duplicates: [],
      platforms: {
        hasOsRestrictions: false,
        hasCpuRestrictions: false,
        hasEngineRestrictions: false
      },
      fileSize: 0,
      integrityAlgorithms: new Set()
    };

    // Analyze packages (lockfileVersion 2/3)
    if (lockData.packages) {
      const packages = lockData.packages;

      Object.entries(packages).forEach(([key, value]) => {
        if (key === '') return; // skip root

        analysis.dependencies.total++;

        // Track resolved registries
        if (value.resolved) {
          try {
            const url = new URL(value.resolved);
            analysis.registries.add(url.origin);
          } catch (e) {
            // git or file dependencies
          }
        }

        // Track integrity algorithms
        if (value.integrity) {
          const algo = value.integrity.split('-')[0];
          analysis.integrityAlgorithms.add(algo);
        }

        // Check platform restrictions
        if (value.os) analysis.platforms.hasOsRestrictions = true;
        if (value.cpu) analysis.platforms.hasCpuRestrictions = true;
        if (value.engines) analysis.platforms.hasEngineRestrictions = true;
      });
    }
    // Fallback for lockfileVersion 1
    else if (lockData.dependencies) {
      const countDeps = (deps) => {
        Object.entries(deps).forEach(([name, info]) => {
          analysis.dependencies.total++;
          if (info.resolved) {
            try {
              const url = new URL(info.resolved);
              analysis.registries.add(url.origin);
            } catch (e) { /* skip */ }
          }
          if (info.integrity) {
            const algo = info.integrity.split('-')[0];
            analysis.integrityAlgorithms.add(algo);
          }
          if (info.dependencies) {
            countDeps(info.dependencies);
          }
        });
      };
      countDeps(lockData.dependencies);
    }

    // Find duplicate packages (different versions of same package)
    if (lockData.packages) {
      const packageVersions = {};
      Object.entries(lockData.packages).forEach(([key, value]) => {
        if (key === '') return;
        const name = key.replace(/^node_modules\//, '').replace(/.*node_modules\//, '');
        if (!packageVersions[name]) packageVersions[name] = [];
        if (value.version) {
          packageVersions[name].push({
            version: value.version,
            path: key
          });
        }
      });

      Object.entries(packageVersions).forEach(([name, versions]) => {
        const uniqueVersions = [...new Set(versions.map(v => v.version))];
        if (uniqueVersions.length > 1) {
          analysis.duplicates.push({
            name,
            versions: uniqueVersions,
            instances: versions.length
          });
        }
      });
    }

    // File size
    const stats = fs.statSync(this.packageLockPath);
    analysis.fileSize = stats.size;
    analysis.fileSizeReadable = this.formatBytes(stats.size);

    // Convert sets to arrays for serialization
    analysis.registries = [...analysis.registries];
    analysis.integrityAlgorithms = [...analysis.integrityAlgorithms];

    this.log('SUCCESS', `Analysis complete: ${analysis.dependencies.total} total packages`);
    this.log('INFO', `  Direct: ${analysis.dependencies.direct}, Dev: ${analysis.dependencies.dev}`);
    this.log('INFO', `  Registries: ${analysis.registries.join(', ')}`);
    this.log('INFO', `  Duplicates: ${analysis.duplicates.length} packages have multiple versions`);
    this.log('INFO', `  Lock file size: ${analysis.fileSizeReadable}`);

    return analysis;
  }

  /**
   * Get information about a specific package from the lock file
   */
  getPackageInfo(packageName) {
    if (!fs.existsSync(this.packageLockPath)) {
      throw new Error('package-lock.json not found');
    }

    const lockData = JSON.parse(fs.readFileSync(this.packageLockPath, 'utf8'));

    const info = {
      name: packageName,
      found: false,
      versions: [],
      locations: []
    };

    if (lockData.packages) {
      Object.entries(lockData.packages).forEach(([key, value]) => {
        if (key === '') return;
        const name = key.replace(/^node_modules\//, '').replace(/.*node_modules\//, '');
        if (name === packageName) {
          info.found = true;
          info.versions.push(value.version);
          info.locations.push({
            path: key,
            version: value.version,
            resolved: value.resolved,
            integrity: value.integrity,
            dev: value.dev || false,
            optional: value.optional || false,
            peer: value.peer || false
          });
        }
      });
    }

    return info;
  }

  /**
   * Compare two lock files and show differences
   */
  compareLockFiles(lockFilePath1, lockFilePath2) {
    this.log('INFO', 'Comparing lock files...');

    const lock1 = JSON.parse(fs.readFileSync(lockFilePath1, 'utf8'));
    const lock2 = JSON.parse(fs.readFileSync(lockFilePath2, 'utf8'));

    const getPackageMap = (lockData) => {
      const map = {};
      const packages = lockData.packages || {};
      Object.entries(packages).forEach(([key, value]) => {
        if (key === '') return;
        const name = key.replace(/^node_modules\//, '').replace(/.*node_modules\//, '');
        if (!map[name]) map[name] = [];
        map[name].push(value.version);
      });
      // Fallback for older lockfile versions
      if (Object.keys(map).length === 0 && lockData.dependencies) {
        const extractDeps = (deps) => {
          Object.entries(deps).forEach(([name, info]) => {
            if (!map[name]) map[name] = [];
            map[name].push(info.version);
            if (info.dependencies) extractDeps(info.dependencies);
          });
        };
        extractDeps(lockData.dependencies);
      }
      return map;
    };

    const map1 = getPackageMap(lock1);
    const map2 = getPackageMap(lock2);

    const allPackages = new Set([...Object.keys(map1), ...Object.keys(map2)]);

    const diff = {
      added: [],
      removed: [],
      changed: [],
      unchanged: 0
    };

    allPackages.forEach(name => {
      const versions1 = (map1[name] || []).sort();
      const versions2 = (map2[name] || []).sort();

      if (!map1[name]) {
        diff.added.push({ name, versions: versions2 });
      } else if (!map2[name]) {
        diff.removed.push({ name, versions: versions1 });
      } else if (JSON.stringify(versions1) !== JSON.stringify(versions2)) {
        diff.changed.push({
          name,
          from: versions1,
          to: versions2
        });
      } else {
        diff.unchanged++;
      }
    });

    this.log('INFO', `Comparison results:`);
    this.log('INFO', `  Added: ${diff.added.length}`);
    this.log('INFO', `  Removed: ${diff.removed.length}`);
    this.log('INFO', `  Changed: ${diff.changed.length}`);
    this.log('INFO', `  Unchanged: ${diff.unchanged}`);

    return diff;
  }

  // ============================================================
  // SECTION 5: CI/CD Pipeline Integration
  // ============================================================

  /**
   * Generate a deployment-ready configuration
   * This creates scripts and configs for common CI/CD platforms
   */
  generateCIConfig(platform = 'github-actions') {
    const configs = {};

    // GitHub Actions workflow
    configs['github-actions'] = `# .github/workflows/ci.yml
# Generated by PackageLockManager
name: CI

on:
  push:
    branches: [main, develop]
  pull_request:
    branches: [main]

jobs:
  build:
    runs-on: ubuntu-latest

    strategy:
      matrix:
        node-version: [18.x, 20.x]

    steps:
      - uses: actions/checkout@v4

      - name: Use Node.js \${{ matrix.node-version }}
        uses: actions/setup-node@v4
        with:
          node-version: \${{ matrix.node-version }}
          cache: 'npm'

      # CRITICAL: Use npm ci, NOT npm install in CI
      # npm ci:
      #   - Requires package-lock.json to exist
      #   - Removes existing node_modules
      #   - Installs exact versions from lock file
      #   - Fails if lock file is out of sync with package.json
      #   - Is faster than npm install
      - name: Install dependencies
        run: npm ci

      - name: Run linting
        run: npm run lint --if-present

      - name: Run tests
        run: npm test

      - name: Security audit
        run: npm audit --audit-level=high

  deploy:
    needs: build
    runs-on: ubuntu-latest
    if: github.ref == 'refs/heads/main'

    steps:
      - uses: actions/checkout@v4

      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: '20.x'
          cache: 'npm'

      # Production install - excludes devDependencies
      - name: Install production dependencies
        run: npm ci --omit=dev

      - name: Build
        run: npm run build --if-present

      - name: Deploy
        run: echo "Add your deployment steps here"
`;

    // GitLab CI
    configs['gitlab-ci'] = `# .gitlab-ci.yml
# Generated by PackageLockManager
image: node:20

cache:
  key:
    files:
      - package-lock.json
  paths:
    - node_modules/

stages:
  - install
  - test
  - build
  - deploy

install:
  stage: install
  script:
    - npm ci
  artifacts:
    paths:
      - node_modules/
    expire_in: 1 hour

test:
  stage: test
  script:
    - npm test
  dependencies:
    - install

audit:
  stage: test
  script:
    - npm audit --audit-level=high
  allow_failure: true
  dependencies:
    - install

build:
  stage: build
  script:
    - npm run build
  artifacts:
    paths:
      - dist/
    expire_in: 1 week
  dependencies:
    - install

deploy:
  stage: deploy
  script:
    - npm ci --omit=dev
    - echo "Add deployment steps here"
  only:
    - main
  dependencies:
    - build
`;

    // Jenkins
    configs['jenkins'] = `// Jenkinsfile
// Generated by PackageLockManager
pipeline {
    agent {
        docker {
            image 'node:20'
        }
    }

    environment {
        NPM_CONFIG_CACHE = '\${WORKSPACE}/.npm'
        CI = 'true'
    }

    stages {
        stage('Install') {
            steps {
                // Always use npm ci in CI environments
                sh 'npm ci'
            }
        }

        stage('Lint') {
            steps {
                sh 'npm run lint || true'
            }
        }

        stage('Test') {
            steps {
                sh 'npm test'
            }
        }

        stage('Security Audit') {
            steps {
                sh 'npm audit --audit-level=high || true'
            }
        }

        stage('Build') {
            steps {
                sh 'npm run build'
            }
        }

        stage('Deploy') {
            when {
                branch 'main'
            }
            steps {
                sh 'npm ci --omit=dev'
                sh 'echo "Add deployment commands"'
            }
        }
    }

    post {
        always {
            cleanWs()
        }
    }
}
`;

    // Docker
    configs['docker'] = `# Dockerfile
# Generated by PackageLockManager
# Multi-stage build for optimal image size

# ---- Build Stage ----
FROM node:20-alpine AS builder

WORKDIR /app

# IMPORTANT: Copy BOTH package.json AND package-lock.json
# This ensures Docker cache is used when dependencies haven't changed
COPY package.json package-lock.json ./

# Use npm ci for deterministic, reproducible installs
RUN npm ci

# Copy source code (after npm ci to leverage Docker layer caching)
COPY . .

RUN npm run build

# ---- Production Stage ----
FROM node:20-alpine AS production

WORKDIR /app

# Copy package files
COPY package.json package-lock.json ./

# Install only production dependencies
RUN npm ci --omit=dev && npm cache clean --force

# Copy built artifacts from builder stage
COPY --from=builder /app/dist ./dist

# Create non-root user for security
RUN addgroup -g 1001 -S nodejs && \\
    adduser -S nodeuser -u 1001 -G nodejs

USER nodeuser

EXPOSE 3000

CMD ["node", "dist/index.js"]
`;

    // .npmrc best practices
    configs['npmrc'] = `# .npmrc
# Generated by PackageLockManager
# Best practices for consistent dependency management

# Ensure package-lock.json is always generated/updated
package-lock=true

# Use exact versions when adding new dependencies
# This reduces ambiguity and makes updates intentional
# save-exact=true

# Engine strictness - fail if Node.js version doesn't match
engine-strict=true

# Audit on install
audit=true

# Fund messages off (less noise in CI)
fund=false

# Optional: Use a specific registry
# registry=https://registry.npmjs.org/

# Optional: Scope-specific registries
# @mycompany:registry=https://npm.mycompany.com/
`;

    // .gitignore additions
    configs['gitignore'] = `# Node.js dependency management
# ALWAYS commit package-lock.json for applications
# DO NOT commit it for libraries (publishable packages)

node_modules/
.npm
*.tgz

# DO commit these:
# package.json
# package-lock.json
# .npmrc (if no secrets)
`;

    if (platform && configs[platform]) {
      return configs[platform];
    }

    return configs;
  }

  /**
   * Pre-deploy validation checklist
   * Run this before any deployment to ensure everything is in order
   */
  preDeployCheck() {
    this.log('INFO', '=== Pre-Deployment Check ===');

    const results = {
      passed: true,
      checks: []
    };

    // Check 1: Lock file exists
    const lockExists = fs.existsSync(this.packageLockPath);
    results.checks.push({
      name: 'Lock file exists',
      passed: lockExists,
      message: lockExists ? 'package-lock.json found' : 'MISSING: package-lock.json not found'
    });
    if (!lockExists) results.passed = false;

    // Check 2: Package.json exists
    const packageExists = fs.existsSync(this.packageJsonPath);
    results.checks.push({
      name: 'Package.json exists',
      passed: packageExists,
      message: packageExists ? 'package.json found' : 'MISSING: package.json not found'
    });
    if (!packageExists) results.passed = false;

    if (!lockExists || !packageExists) {
      this.log('ERROR', 'Critical files missing. Cannot proceed with deployment.');
      return results;
    }

    // Check 3: Lock file is valid JSON
    let lockValid = true;
    try {
      JSON.parse(fs.readFileSync(this.packageLockPath, 'utf8'));
    } catch (e) {
      lockValid = false;
    }
    results.checks.push({
      name: 'Lock file is valid JSON',
      passed: lockValid,
      message: lockValid ? 'Valid JSON' : 'INVALID: Lock file contains syntax errors'
    });
    if (!lockValid) results.passed = false;

    // Check 4: Lock file in sync
    try {
      const validation = this.validateLockFile();
      results.checks.push({
        name: 'Lock file in sync with package.json',
        passed: validation.valid,
        message: validation.valid
          ? 'Lock file is in sync'
          : `OUT OF SYNC: ${validation.issues.join('; ')}`
      });
      if (!validation.valid) results.passed = false;
    } catch (e) {
      results.checks.push({
        name: 'Lock file in sync with package.json',
        passed: false,
        message: `ERROR: ${e.message}`
      });
      results.passed = false;
    }

    // Check 5: No .npmrc with credentials committed
    const npmrcPath = path.join(this.projectRoot, '.npmrc');
    if (fs.existsSync(npmrcPath)) {
      const npmrcContent = fs.readFileSync(npmrcPath, 'utf8');
      const hasTokens = npmrcContent.includes('_authToken') || npmrcContent.includes('_password');
      results.checks.push({
        name: 'No credentials in .npmrc',
        passed: !hasTokens,
        message: hasTokens
          ? 'WARNING: .npmrc may contain authentication tokens'
          : '.npmrc is safe (no tokens found)'
      });
      if (hasTokens) results.passed = false;
    }

    // Check 6: Node.js version compatibility
    const packageJson = JSON.parse(fs.readFileSync(this.packageJsonPath, 'utf8'));
    if (packageJson.engines && packageJson.engines.node) {
      const { satisfies } = require('semver');
      const nodeVersionOk = satisfies(process.version, packageJson.engines.node);
      results.checks.push({
        name: 'Node.js version compatible',
        passed: nodeVersionOk,
        message: nodeVersionOk
          ? `Node.js ${process.version} satisfies "${packageJson.engines.node}"`
          : `Node.js ${process.version} does NOT satisfy "${packageJson.engines.node}"`
      });
      if (!nodeVersionOk) results.passed = false;
    }

    // Check 7: Lockfile version check
    if (lockValid) {
      const lockData = JSON.parse(fs.readFileSync(this.packageLockPath, 'utf8'));
      const modernLock = lockData.lockfileVersion >= 2;
      results.checks.push({
        name: 'Modern lockfile version',
        passed: modernLock,
        message: modernLock
          ? `Lockfile version ${lockData.lockfileVersion} (modern)`
          : `Lockfile version ${lockData.lockfileVersion} - consider upgrading npm to get version 2+`
      });
    }

    // Print results
    this.log('INFO', '');
    this.log('INFO', 'Pre-Deployment Check Results:');
    this.log('INFO', '─'.repeat(60));

    results.checks.forEach(check => {
      const icon = check.passed ? '✅' : '❌';
      this.log(check.passed ? 'SUCCESS' : 'ERROR', `${icon} ${check.name}: ${check.message}`);
    });

    this.log('INFO', '─'.repeat(60));
    this.log(
      results.passed ? 'SUCCESS' : 'ERROR',
      results.passed
        ? '✅ All checks passed - ready for deployment'
        : '❌ Some checks failed - fix issues before deploying'
    );

    return results;
  }

  // ============================================================
  // SECTION 6: Utility Methods
  // ============================================================

  computeLockHash() {
    const content = fs.readFileSync(this.packageLockPath, 'utf8');
    return crypto.createHash('sha256').update(content).digest('hex');
  }

  storeLockHash() {
    if (fs.existsSync(this.packageLockPath)) {
      const hash = this.computeLockHash();
      fs.writeFileSync(this.lockHashPath, hash);
      this.log('INFO', `Lock file hash stored: ${hash.substring(0, 12)}...`);
    }
  }

  cleanArtifacts() {
    const nodeModulesPath = path.join(this.projectRoot, 'node_modules');
    if (fs.existsSync(nodeModulesPath)) {
      fs.rmSync(nodeModulesPath, { recursive: true, force: true });
    }
    if (fs.existsSync(this.packageLockPath)) {
      fs.unlinkSync(this.packageLockPath);
    }
  }

  getNpmVersion() {
    try {
      return execSync('npm --version', { stdio: 'pipe' }).toString().trim();
    } catch (e) {
      return 'unknown';
    }
  }

  formatBytes(bytes) {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  }

  log(level, message) {
    const timestamp = new Date().toISOString();
    const colors = {
      INFO: '\x1b[36m',     // cyan
      SUCCESS: '\x1b[32m',  // green
      WARNING: '\x1b[33m',  // yellow
      ERROR: '\x1b[31m',    // red
    };
    const reset = '\x1b[0m';
    const color = colors[level] || '';

    const entry = { timestamp, level, message };
    this.logEntries.push(entry);

    console.log(`${color}[${level}]${reset} ${message}`);
  }

  getLog() {
    return this.logEntries;
  }
}

// ============================================================
// SECTION 7: CLI Interface
// ============================================================

function printHelp() {
  console.log(`
╔══════════════════════════════════════════════════════════════╗
║           Package Lock Manager - CLI Reference               ║
╚══════════════════════════════════════════════════════════════╝

Usage: node package-lock-manager.js <command> [options]

Commands:
  generate          Generate a fresh package-lock.json
  validate          Validate lock file is in sync with package.json
  analyze           Analyze lock file and show detailed report
  integrity         Check if lock file has been modified
  ci-install        Run CI-safe install (npm ci)
  audit             Run security audit
  audit-fix         Run security audit with auto-fix
  update            Check and apply dependency updates
  update-dry        Show what would be updated (dry run)
  pre-deploy        Run pre-deployment validation checks
  compare <f1> <f2> Compare two lock files
  ci-config         Generate CI/CD configuration files
  info <package>    Show info about a specific locked package
  help              Show this help message

Examples:
  node package-lock-manager.js generate
  node package-lock-manager.js validate
  node package-lock-manager.js ci-install
  node package-lock-manager.js ci-install --production
  node package-lock-manager.js update-dry
  node package-lock-manager.js compare old-lock.json new-lock.json
  node package-lock-manager.js info express
  node package-lock-manager.js ci-config github-actions

Best Practices:
  1. ALWAYS commit package-lock.json to version control
  2. Use "npm ci" in CI/CD pipelines, NEVER "npm install"
  3. Run "npm install" only locally during development
  4. Review lock file changes in pull requests
  5. Run security audits regularly
  6. Use exact versions (--save-exact) for critical dependencies
  7. Keep npm updated for latest lockfile format improvements
  `);
}

// Main CLI handler
function main() {
  const args = process.argv.slice(2);
  const command = args[0];
  const manager = new PackageLockManager();

  if (!command || command === 'help' || command === '--help') {
    printHelp();
    return;
  }

  try {
    switch (command) {
      case 'generate':
        manager.generateLockFile();
        break;

      case 'validate':
        const report = manager.validateLockFile();
        console.log('\nValidation Report:');
        console.log(JSON.stringify(report, null, 2));
        break;

      case 'analyze':
        const analysis = manager.analyzeLockFile();
        console.log('\nAnalysis Report:');
        console.log(JSON.stringify(analysis, null, 2));
        break;

      case 'integrity':
        const integrityResult = manager.checkIntegrity();
        console.log('\nIntegrity Check:');
        console.log(JSON.stringify(integrityResult, null, 2));
        break;

      case 'ci-install':
        const production = args.includes('--production');
        const ignoreScripts = args.includes('--ignore-scripts');
        manager.ciInstall({ production, ignoreScripts });
        break;

      case 'audit':
        const auditReport = manager.auditDependencies();
        console.log('\nAudit Report:');
        console.log(JSON.stringify(auditReport, null, 2));
        break;

      case 'audit-fix':
        const fixReport = manager.auditDependencies({ fix: true });
        console.log('\nAudit Fix Report:');
        console.log(JSON.stringify(fixReport, null, 2));
        break;

      case 'update':
        const updateResult = manager.updateDependencies();
        console.log('\nUpdate Result:');
        console.log(JSON.stringify(updateResult, null, 2));
        break;

      case 'update-dry':
        const dryResult = manager.updateDependencies({ dry: true });
        console.log('\nDry Run Result:');
        console.log(JSON.stringify(dryResult, null, 2));
        break;

      case 'pre-deploy':
        manager.preDeployCheck();
        break;

      case 'compare':
        if (args.length < 3) {
          console.error('Usage: compare <file1> <file2>');
          process.exit(1);
        }
        const diff = manager.compareLockFiles(args[1], args[2]);
        console.log('\nComparison Result:');
        console.log(JSON.stringify(diff, null, 2));
        break;

      case 'ci-config': {
        const platform = args[1] || 'all';
        const configs = manager.generateCIConfig();

        if (platform === 'all') {
          Object.entries(configs).forEach(([name, content]) => {
            console.log(`\n${'═'.repeat(60)}`);
            console.log(`Configuration: ${name}`);
            console.log('═'.repeat(60));
            console.log(content);
          });
        } else if (configs[platform]) {
          console.log(configs[platform]);
        } else {
          console.error(`Unknown platform: ${platform}`);
          console.log('Available:', Object.keys(configs).join(', '));
        }
        break;
      }

      case 'info':
        if (!args[1]) {
          console.error('Usage: info <package-name>');
          process.exit(1);
        }
        const info = manager.getPackageInfo(args[1]);
        console.log('\nPackage Info:');
        console.log(JSON.stringify(info, null, 2));
        break;

      default:
        console.error(`Unknown command: ${command}`);
        printHelp();
        process.exit(1);
    }
  } catch (error) {
    console.error(`\n❌ Error: ${error.message}`);
    process.exit(1);
  }
}

// Export for programmatic use
module.exports = { PackageLockManager };

// Run CLI if called directly
if (require.main === module) {
  main();
}